public function currentTime(){
    header('Content-Type: application/json');
    echo json_encode(['server_time' => date('Y-m-d H:i:s')]);
}

public function clearExpiredCard() {
    // Fetch all expired carts after 1 hour
    $expired_carts_query = $this->db->query("SELECT * FROM " . DB_PREFIX . "cart WHERE date_added < DATE_SUB(NOW(), INTERVAL 20 MINUTE)");
    
    if ($expired_carts_query->num_rows) {
        foreach ($expired_carts_query->rows as $cart) {
            // Fetch the product's current reserved stock and restore it
            $product_id = (int)$cart['product_id'];
            $quantity = (int)$cart['quantity'];
    
            // Update the stock for the product by adding back the reserved quantity
            $this->db->query("UPDATE " . DB_PREFIX . "product SET quantity = quantity + '" . $quantity . "' WHERE product_id = '" . $product_id . "'");
    
            // Optionally, remove the reserved stock entry if you have a `reserved_stock` table
            $this->db->query("DELETE FROM " . DB_PREFIX . "reserved_stock WHERE cart_id = '" . (int)$cart['cart_id'] . "'");
        }
    
        // Finally, remove the expired carts after restoring stock
        $this->db->query("DELETE FROM " . DB_PREFIX . "cart WHERE date_added < DATE_SUB(NOW(), INTERVAL 20 MINUTE)");
    }
}

